import{_ as s,c as a,o as n,N as t}from"./chunks/framework.0799945b.js";const l="/assets/03code_cluster_id.83c61aad.jpeg",o="/assets/04code_cluster_id_translate.c2afcf6b.png",u=JSON.parse('{"title":"如果获取 TiDB 集群初始化时间","description":"","frontmatter":{},"headers":[],"relativePath":"zh/tidb/07TiDB-源码阅读/7-1TiDB/03TIDB how to get init time.md"}'),e={name:"zh/tidb/07TiDB-源码阅读/7-1TiDB/03TIDB how to get init time.md"},p=t('<h1 id="如果获取-tidb-集群初始化时间" tabindex="-1">如果获取 TiDB 集群初始化时间 <a class="header-anchor" href="#如果获取-tidb-集群初始化时间" aria-label="Permalink to &quot;如果获取 TiDB 集群初始化时间&quot;">​</a></h1><h2 id="一、前言" tabindex="-1">一、前言 <a class="header-anchor" href="#一、前言" aria-label="Permalink to &quot;一、前言&quot;">​</a></h2><p>        很久没写文章了，今天在同事的提示的情况下，处理了一个 TiDB 获取集群创建时间的问题，觉得有必要记录一下防止遗忘，也分享给大家。</p><h2 id="二、探索" tabindex="-1">二、探索 <a class="header-anchor" href="#二、探索" aria-label="Permalink to &quot;二、探索&quot;">​</a></h2><p>        首先，翻遍 TiDB 官方文档也没有找到能够查询 TiDB 集群初始化时间的方法。所有监控信息（Dashboard、Grafana）都只能仅查询各组件的 Startup Time，查询表的 Create Time 也不准确。<br>         其次，之前知道在集群初始化的时候 PD 会初始化一个 ClusterID 并持久化。即然，TiDB 官方没有提供查询接口，那能够分别集群的也许只有这一个信息了。最开始，一直在尝试使用 pd-ctl 的 <code>tiup ctl:v5.2.3 pd tso 1571036791</code> 直接转译 TSO ，但始终没有成功。<br>         最后在一位同事的提醒下，翻了下 PD 在初始化 Cluster_ID 时的源码,才成功解决问题。详情见 <strong>三、解决</strong> 部分。</p><h2 id="三、解决" tabindex="-1">三、解决 <a class="header-anchor" href="#三、解决" aria-label="Permalink to &quot;三、解决&quot;">​</a></h2><p>        看了下 PD 代码，在这个 <a href="https://github.com/tikv/pd/blob/88409b75418f0de46b62b7121627c23359b571b3/server/util.go#L86-L93" target="_blank" rel="noreferrer">initOrGetClusterID</a> 函数中，Cluster ID 是取当前时间的 Unix 时间戳左移 32 位，再加一个随机数获得。因此直接转译是无法获得正确时间的。</p><p><img src="'+l+'" alt="03code_cluster_id"></p><p>        做了一些小改动，逆着代码思路取出的时间基本符合要求，能确保年月日级别的准确性。大家也可以直接点击 <a href="http://www.dooccn.com/go/#id/7cdec42e1b4f7825c26d8a5343555b5a" target="_blank" rel="noreferrer">代码链接</a> 直接修改其中 Cluster ID 值获取结果。</p><p><img src="'+o+`" alt="04code_cluster_id_translate"></p><p>        其实，之后尝试过右移 32 位再用 pd-ctl tso 转译还是不成功的。估计是因为 TiDB 的 TSO 由 “物理时间+逻辑时间” 组成，而 Cluster ID 的计算由 “物理时间+随机数” 组成吧，本身就不是一个东西吧。</p><h2 id="四、代码逻辑" tabindex="-1">四、代码逻辑 <a class="header-anchor" href="#四、代码逻辑" aria-label="Permalink to &quot;四、代码逻辑&quot;">​</a></h2><div class="language-go"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#89DDFF;">package</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">main</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;">import</span><span style="color:#A6ACCD;"> (</span><span style="color:#89DDFF;">&quot;</span><span style="color:#FFCB6B;">fmt</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">time</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;">func</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">main</span><span style="color:#89DDFF;">()</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"></span>
<span class="line"><span style="color:#A6ACCD;"> </span><span style="color:#676E95;font-style:italic;">//Get from pd.log (cat {{/path/to}}/pd.log|grep &quot;init cluster id&quot;)</span></span>
<span class="line"><span style="color:#A6ACCD;"> </span><span style="color:#676E95;font-style:italic;">//  [2019/10/14 10:35:38.880 +00:00] [INFO] [server.go:212] [&quot;init cluster id&quot;] [cluster-id=6747551640615446306]</span></span>
<span class="line"><span style="color:#A6ACCD;"> history_ts </span><span style="color:#89DDFF;">:=</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">uint64</span><span style="color:#89DDFF;">(</span><span style="color:#F78C6C;">6747551640615446306</span><span style="color:#89DDFF;">)</span></span>
<span class="line"><span style="color:#A6ACCD;"> sub_history_ts </span><span style="color:#89DDFF;">:=</span><span style="color:#A6ACCD;"> history_ts </span><span style="color:#89DDFF;">&gt;&gt;</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">32</span></span>
<span class="line"><span style="color:#A6ACCD;"> ret </span><span style="color:#89DDFF;">:=</span><span style="color:#A6ACCD;"> time</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">Unix</span><span style="color:#89DDFF;">(</span><span style="color:#82AAFF;">int64</span><span style="color:#89DDFF;">(</span><span style="color:#A6ACCD;">sub_history_ts</span><span style="color:#89DDFF;">),</span><span style="color:#F78C6C;">0</span><span style="color:#89DDFF;">)</span></span>
<span class="line"><span style="color:#A6ACCD;"> fmt</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">Println</span><span style="color:#89DDFF;">(</span><span style="color:#A6ACCD;">ret</span><span style="color:#89DDFF;">)</span></span>
<span class="line"><span style="color:#A6ACCD;"> fmt</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">Println</span><span style="color:#89DDFF;">(</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">And the direct &gt;&gt;32 cluster-id is : </span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> sub_history_ts </span><span style="color:#89DDFF;">,</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">,you can try it by pd-ctl,but not correct!!!</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">)</span></span>
<span class="line"><span style="color:#A6ACCD;"> </span><span style="color:#676E95;font-style:italic;">//Although there is random number, but the year/month/day is still accurate </span></span>
<span class="line"><span style="color:#A6ACCD;"> </span><span style="color:#676E95;font-style:italic;">// --&gt; 2019/10/14 vs 2019-10-14</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span>
<span class="line"></span></code></pre></div><p>        希望对大家有帮助！同时，我也把改文章分享在 <a href="https://asktug.com/t/topic/542865" target="_blank" rel="noreferrer">AskTUG-TiDB 如何获取集群创建时间</a> 欢迎交流。</p>`,14),r=[p];function c(i,D,y,F,d,C){return n(),a("div",null,r)}const _=s(e,[["render",c]]);export{u as __pageData,_ as default};
